def move_zeroes(nums):
    write = 0  # position to write next non-zero

    # Pass 1: move all non-zeros to the front
    for read in range(len(nums)):
        if nums[read] != 0:
            nums[write] = nums[read]
            write += 1

    # Pass 2: fill remaining positions with zeros
    while write < len(nums):
        nums[write] = 0
        write += 1

    return nums

# Alternative: swap-based single pass
def move_zeroes_swap(nums):
    write = 0
    for read in range(len(nums)):
        if nums[read] != 0:
            nums[write], nums[read] = nums[read], nums[write]
            write += 1
    return nums

# Example
print(move_zeroes([0, 1, 0, 3, 12]))  # [1, 3, 12, 0, 0]
print(move_zeroes([0, 0, 1]))          # [1, 0, 0]

def subarray_with_given_sum(arr, target):
    """Find if any subarray sums to target (non-negative integers).
    Returns (start, end) indices or (-1, -1)."""
    left = 0
    current_sum = 0

    for right in range(len(arr)):
        current_sum += arr[right]

        # Shrink window from left while sum exceeds target
        while current_sum > target and left <= right:
            current_sum -= arr[left]
            left += 1

        if current_sum == target:
            return (left, right)

    return (-1, -1)


def min_subarray_length(target, nums):
    """Smallest subarray with sum >= target (LeetCode 209)."""
    left = 0
    current_sum = 0
    min_len = float('inf')

    for right in range(len(nums)):
        current_sum += nums[right]
        while current_sum >= target:
            min_len = min(min_len, right - left + 1)
            current_sum -= nums[left]
            left += 1

    return min_len if min_len != float('inf') else 0


# Example
print(subarray_with_given_sum([1, 4, 20, 3, 10, 5], 33))  # (2, 4)
print(min_subarray_length(7, [2, 3, 1, 2, 4, 3]))          # 2

def trap(height):
    """Two-pointer approach - O(n) time, O(1) space."""
    if not height:
        return 0

    left, right = 0, len(height) - 1
    max_left = max_right = 0
    water = 0

    while left < right:
        if height[left] <= height[right]:
            # Left side is the bottleneck
            if height[left] >= max_left:
                max_left = height[left]
            else:
                water += max_left - height[left]
            left += 1
        else:
            # Right side is the bottleneck
            if height[right] >= max_right:
                max_right = height[right]
            else:
                water += max_right - height[right]
            right -= 1

    return water


def trap_prefix(height):
    """Prefix array approach - O(n) time, O(n) space (easier to explain)."""
    n = len(height)
    max_left  = [0] * n
    max_right = [0] * n

    max_left[0] = height[0]
    for i in range(1, n):
        max_left[i] = max(max_left[i-1], height[i])

    max_right[n-1] = height[n-1]
    for i in range(n-2, -1, -1):
        max_right[i] = max(max_right[i+1], height[i])

    return sum(min(max_left[i], max_right[i]) - height[i] for i in range(n))


# Example
print(trap([0, 1, 0, 2, 1, 0, 1, 3, 2, 1, 2, 1]))  # 6
print(trap([4, 2, 0, 3, 2, 5]))                      # 9

import heapq

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def merge_k_lists(lists):
    """Min-heap approach - O(N log K)."""
    heap = []

    # Seed heap with the head of each non-empty list
    for i, node in enumerate(lists):
        if node:
            heapq.heappush(heap, (node.val, i, node))

    dummy = ListNode(0)
    current = dummy

    while heap:
        val, i, node = heapq.heappop(heap)
        current.next = node
        current = current.next

        if node.next:
            heapq.heappush(heap, (node.next.val, i, node.next))

    return dummy.next


def merge_two_lists(l1, l2):
    """Helper for divide-and-conquer approach."""
    dummy = ListNode(0)
    curr = dummy
    while l1 and l2:
        if l1.val <= l2.val:
            curr.next, l1 = l1, l1.next
        else:
            curr.next, l2 = l2, l2.next
        curr = curr.next
    curr.next = l1 or l2
    return dummy.next


def merge_k_lists_dc(lists):
    """Divide-and-conquer approach - same O(N log K) complexity."""
    if not lists:
        return None
    while len(lists) > 1:
        merged = []
        for i in range(0, len(lists), 2):
            l1 = lists[i]
            l2 = lists[i+1] if i+1 < len(lists) else None
            merged.append(merge_two_lists(l1, l2))
        lists = merged
    return lists[0]

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right


def lowest_common_ancestor(root, p, q):
    """LCA for general binary tree - O(n) time, O(h) space."""
    # Base case
    if root is None:
        return None
    # Found one of the targets
    if root == p or root == q:
        return root

    # Search both subtrees
    left  = lowest_common_ancestor(root.left, p, q)
    right = lowest_common_ancestor(root.right, p, q)

    # Both sides found a target -> current node is LCA
    if left and right:
        return root

    # Only one side found a target -> propagate it upward
    return left if left else right


def lca_bst(root, p, q):
    """LCA for BST - O(log n) by using ordering property."""
    if root is None:
        return None
    if p.val < root.val and q.val < root.val:
        return lca_bst(root.left, p, q)   # both in left subtree
    if p.val > root.val and q.val > root.val:
        return lca_bst(root.right, p, q)  # both in right subtree
    return root  # split point — current node is LCA

